#!/bin/sh
# Generated by `harness eval bootstrap` — PROJECT-SPECIFIC grader SKELETON.
# Gates every release/content build by failing if personal data can reach Aurora, Bedrock, S3, logs, or the Next.js client without passing the redaction/pseudonymisation node first, or if data-subject-erasure and Guardrails PII filtering are absent — block on any merge or deploy that touches evidence collection, persistence, prompts, logging, or user-facing rendering.
# Exit 0 = pass, non-zero = fail. Fill the `# TODO` checks against the
# implemented code, then flip the eval's failure→"block-change" to enforce.
#   source: https://gdpr-info.eu/art-32-gdpr/
#   source: https://gdpr.eu/article-32-security-of-processing/
#   source: https://www.edpb.europa.eu/system/files/2025-01/edpb_guidelines_202501_pseudonymisation_en.pdf
#   source: https://www.hunton.com/insights/publications/edpb-advises-on-pseudonymisation-for-gdpr-compliance
#   source: https://gdprlocal.com/large-language-models-llm-gdpr/
#   source: https://arxiv.org/pdf/2510.03662
# GDPR compliance gate for the release-to-content engine.
# PASS (exit 0): personal data is redacted/pseudonymised BEFORE it crosses any
#   persistence/model/transport/log boundary, Guardrails PII filtering is on,
#   and a data-subject-erasure path exists.
# FAIL (non-zero): any path lets raw personal data escape, or a required
#   control is missing/unverified.
# Grounding: GDPR Art.5(1)(c) data minimisation, Art.17 erasure, Art.32 security
#   (pseudonymisation/encryption); EDPB Guidelines 01/2025 on pseudonymisation
#   (pseudonymised data is STILL personal data, so redaction must precede use).
set -eu

fail() { echo "GDPR-GATE FAIL: $1"; exit 1; }
ROOT="$(pwd)"

# Prefer ripgrep; fall back to grep -r.
if command -v rg >/dev/null 2>&1; then SEARCH='rg -n --no-heading'; else SEARCH='grep -rn'; fi
search() { $SEARCH "$@" 2>/dev/null || true; }

# ---------------------------------------------------------------------------
# 0. Repo must exist with a recognisable source tree (skeleton-safe sanity).
# ---------------------------------------------------------------------------
[ -d "$ROOT" ] || fail "working directory missing"

# ---------------------------------------------------------------------------
# 1. NEVER: secrets / personal data committed in cleartext to the repo.
#    (Secrets Manager is deferred per spec; env files must not be tracked.)
# ---------------------------------------------------------------------------
if command -v git >/dev/null 2>&1 && git -C "$ROOT" rev-parse --git-dir >/dev/null 2>&1; then
  if git -C "$ROOT" ls-files | grep -E '(^|/)\.env($|\.)' | grep -vE '\.env\.(example|sample|template)$' >/dev/null; then
    fail "a real .env file is tracked in git (Art.32 confidentiality)"
  fi
fi
# Hardcoded credential-looking literals in source.
if search -e 'AKIA[0-9A-Z]{16}' -e 'xi-api-key["'\'' ]*[:=]["'\'' ]*[A-Za-z0-9]' \
     --glob '!**/node_modules/**' --glob '!**/*.test.*' . | grep . >/dev/null 2>&1; then
  fail "hardcoded AWS/ElevenLabs credential literal found in source"
fi

# ---------------------------------------------------------------------------
# 2. A redaction/pseudonymisation stage MUST exist (Art.5(1)(c), Art.32(1)(a)).
#    Spec flow: collect_evidence -> redact_evidence -> persist_evidence.
# ---------------------------------------------------------------------------
if ! search -e 'redact_evidence' -e 'redact(_|[A-Z])' -e 'pseudonymi' . | grep . >/dev/null 2>&1; then
  fail "no redaction/pseudonymisation node found (expected redact_evidence before persist)"
fi

# ---------------------------------------------------------------------------
# 3. NEVER: persist evidence to Aurora or call Bedrock BEFORE redaction.
#    Code-specific ordering check — cannot be proven by grep alone.
# ---------------------------------------------------------------------------
# TODO: assert in the LangGraph release_intelligence_graph that the edge
#       collect_* -> ... -> persist_evidence/cluster_features_with_bedrock
#       is unreachable without traversing redact_evidence. Implement a graph
#       lint (e.g. a pytest that loads the compiled graph and checks every
#       path into persist_evidence and into any Bedrock-calling node passes
#       through the redaction node) and invoke it here.
GRAPH_LINT="tests/test_redaction_ordering.py"   # adjust to real path
if [ -f "$GRAPH_LINT" ]; then
  if command -v pytest >/dev/null 2>&1; then
    pytest -q "$GRAPH_LINT" >/dev/null 2>&1 || fail "redaction-ordering graph lint failed ($GRAPH_LINT)"
  else
    fail "pytest unavailable to run redaction-ordering lint"
  fi
else
  echo "GDPR-GATE TODO: redaction-ordering graph lint ($GRAPH_LINT) not implemented"
  exit 1
fi

# ---------------------------------------------------------------------------
# 4. Bedrock Guardrails with PII filtering MUST be wired into model calls
#    (Art.32 + spec's 'PII/sensitive info checks').
# ---------------------------------------------------------------------------
if ! search -e 'guardrailIdentifier' -e 'guardrailVersion' -e 'GuardrailConfig' . | grep . >/dev/null 2>&1; then
  fail "Bedrock Converse calls have no Guardrail attached (no guardrailIdentifier)"
fi
# TODO: verify the referenced guardrail actually enables PII/SENSITIVE_INFORMATION
#       filters set to ANONYMIZE/BLOCK (assert against guardrail config/IaC).
GUARDRAIL_CFG="infra/guardrails.json"   # adjust to real path
if [ -f "$GUARDRAIL_CFG" ] && command -v jq >/dev/null 2>&1; then
  jq -e '.. | objects | select(.type=="sensitiveInformationPolicyConfig" or has("piiEntitiesConfig"))' \
    "$GUARDRAIL_CFG" >/dev/null 2>&1 || fail "guardrail config lacks a PII/sensitive-information policy"
else
  echo "GDPR-GATE TODO: guardrail PII-policy config ($GUARDRAIL_CFG) not present/checkable"
  exit 1
fi

# ---------------------------------------------------------------------------
# 5. NEVER: log raw personal data / evidence bodies.
#    Code-specific — needs structured-logging redaction assertion.
# ---------------------------------------------------------------------------
# Heuristic smell test: logging an entire evidence/PII payload.
if search -e 'print\(.*(evidence|email|pii|personal_data)' \
          -e 'console\.log\(.*(evidence|email|pii|personalData)' \
          -e 'log(ger)?\.(info|debug|warning)\(.*(evidence_body|raw_diff|pii)' \
     --glob '!**/*.test.*' . | grep . >/dev/null 2>&1; then
  fail "a log/print statement appears to emit raw evidence/PII"
fi
# TODO: assert the logger is configured with a PII-scrubbing filter/processor
#       (e.g. structlog processor or pino redact paths) covering email, names,
#       tokens, and evidence bodies. Replace exit 1 once verified.
echo "GDPR-GATE TODO: confirm logger PII-scrubbing filter is configured"
exit 1

# ---------------------------------------------------------------------------
# 6. NEVER: ship unredacted personal data to the Next.js client.
#    TODO: assert server components / API routes strip PII fields from
#          evidence before returning to the browser (no raw evidence body in
#          any `app/**/route.ts` JSON response or RSC prop).
# ---------------------------------------------------------------------------
# (Unreached until §5 TODO resolved; kept for completeness.)

# ---------------------------------------------------------------------------
# 7. Data-subject rights: an erasure path MUST exist (Art.17).
#    TODO: assert a route/handler that deletes a subject's evidence rows from
#          Aurora AND the corresponding S3 objects AND vector embeddings.
# ---------------------------------------------------------------------------
# if ! search -e 'erasure' -e 'right_to_be_forgotten' -e 'delete_subject' . | grep . >/dev/null; then
#   fail "no data-subject erasure path (Art.17) found"
# fi

echo "GDPR-GATE PASS: redaction-before-use, Guardrail PII filtering, log scrubbing, and erasure path all verified"
exit 0

